## 7. CORE IMPLEMENTATION PATTERNS

### 7.1 Main Provider Factory

**File:** `packages/mistral/src/mistral-provider.ts` (Key excerpt)

```typescript
import {
  EmbeddingModelV3,
  LanguageModelV3,
  NoSuchModelError,
  ProviderV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';

export interface MistralProvider extends ProviderV3 {
  (modelId: MistralChatModelId): LanguageModelV3;
  languageModel(modelId: MistralChatModelId): LanguageModelV3;
  chat(modelId: MistralChatModelId): LanguageModelV3;
  embedding(modelId: MistralEmbeddingModelId): EmbeddingModelV3;
  embeddingModel: (modelId: MistralEmbeddingModelId) => EmbeddingModelV3;
  textEmbedding(modelId: MistralEmbeddingModelId): EmbeddingModelV3;
  textEmbeddingModel(modelId: MistralEmbeddingModelId) => EmbeddingModelV3;
}

export interface MistralProviderSettings {
  baseURL?: string;
  apiKey?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
  generateId?: () => string;
}

export function createMistral(
  options: MistralProviderSettings = {},
): MistralProvider {
  const baseURL = withoutTrailingSlash(options.baseURL) ?? 'https://api.mistral.ai/v1';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'MISTRAL_API_KEY',
          description: 'Mistral',
        })}`,
        ...options.headers,
      },
      `ai-sdk/mistral/${VERSION}`,
    );

  const createChatModel = (modelId: MistralChatModelId) =>
    new MistralChatLanguageModel(modelId, {
      provider: 'mistral.chat',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
      generateId: options.generateId,
    });

  const provider = function (modelId: MistralChatModelId) {
    if (new.target) {
      throw new Error(
        'The Mistral model function cannot be called with the new keyword.',
      );
    }
    return createChatModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createChatModel;
  provider.chat = createChatModel;
  provider.embedding = createEmbeddingModel;

  return provider;
}

export const mistral = createMistral();
```

**Key patterns:**
- Provider is a factory function + object with methods
- Settings interface for configuration (baseURL, apiKey, headers, fetch, generateId)
- Uses `loadApiKey` to get API key from options or env vars
- Uses `withUserAgentSuffix` to add SDK version info
- Returns default instance alongside factory function

