150	    }
151	
152	    const headerBytes = partData.slice(0, headerEnd);
153	    const headerStr = new TextDecoder().decode(headerBytes);
154	    const headers: Record<string, string> = {};
155	    for (const line of headerStr.split(/\r?\n/)) {
156	      const colonIdx = line.indexOf(':');
157	      if (colonIdx > 0) {
158	        const key = line.slice(0, colonIdx).trim().toLowerCase();
159	        const value = line.slice(colonIdx + 1).trim();
