179	interface VideoMultipartResult {
180	  jobResult: ProdiaJobResult;
181	  videoBytes: Uint8Array;
182	  videoMediaType: string;
183	}
184	
185	function createVideoMultipartResponseHandler() {
186	  return async ({
187	    response,
188	  }: {
189	    response: Response;
190	  }): Promise<{
191	    value: VideoMultipartResult;
192	    responseHeaders: Record<string, string>;
193	  }> => {
194	    const contentType = response.headers.get('content-type') ?? '';
195	    const responseHeaders: Record<string, string> = {};
196	    response.headers.forEach((value, key) => {
197	      responseHeaders[key] = value;
198	    });
199	
200	    const boundaryMatch = contentType.match(/boundary=([^\s;]+)/);
201	    if (!boundaryMatch) {
202	      throw new Error(
203	        `Prodia response missing multipart boundary in content-type: ${contentType}`,
204	      );
205	    }
206	    const boundary = boundaryMatch[1];
207	
208	    const arrayBuffer = await response.arrayBuffer();
209	    const bytes = new Uint8Array(arrayBuffer);
210	
211	    const parts = parseMultipart(bytes, boundary);
212	
213	    let jobResult: ProdiaJobResult | undefined;
214	    let videoBytes: Uint8Array | undefined;
215	    let videoMediaType = 'video/mp4';
216	
217	    for (const part of parts) {
218	      const contentDisposition = part.headers['content-disposition'] ?? '';
219	      const partContentType = part.headers['content-type'] ?? '';
220	
221	      if (contentDisposition.includes('name="job"')) {
222	        const jsonStr = new TextDecoder().decode(part.body);
223	        jobResult = await parseJSON({
224	          text: jsonStr,
225	          schema: zodSchema(prodiaJobResultSchema),
226	        });
227	      } else if (contentDisposition.includes('name="output"')) {
228	        videoBytes = part.body;
229	        if (partContentType.startsWith('video/')) {
230	          videoMediaType = partContentType;
231	        }
232	      } else if (partContentType.startsWith('video/')) {
233	        videoBytes = part.body;
234	        videoMediaType = partContentType;
235	      }
236	    }
237	
238	    if (!jobResult) {
239	      throw new Error('Prodia multipart response missing job part');
240	    }
241	    if (!videoBytes) {
242	      throw new Error('Prodia multipart response missing output video');
243	    }
244	
245	    return {
246	      value: { jobResult, videoBytes, videoMediaType },
247	      responseHeaders,
248	    };
249	  };
250	}
