252	async function resolveVideoFileData(
253	  file: NonNullable<
254	    Parameters<Experimental_VideoModelV3['doGenerate']>[0]['image']
255	  >,
256	  fetchFunction?: FetchFunction,
257	): Promise<{ bytes: Uint8Array; mediaType: string }> {
258	  if (file.type === 'file') {
259	    const data =
260	      typeof file.data === 'string'
261	        ? convertBase64ToUint8Array(file.data)
262	        : file.data;
263	    return { bytes: data, mediaType: file.mediaType };
264	  }
265	  // URL type - fetch the data
266	  const response = await (fetchFunction ?? globalThis.fetch)(file.url);
267	  const arrayBuffer = await response.arrayBuffer();
268	  const mediaType =
269	    response.headers.get('content-type') ?? 'application/octet-stream';
270	  return { bytes: new Uint8Array(arrayBuffer), mediaType };
271	}
272	
273	function getExtension(mediaType: string): string {
274	  const map: Record<string, string> = {
275	    'image/png': '.png',
276	    'image/jpeg': '.jpg',
277	    'image/webp': '.webp',
278	    'video/mp4': '.mp4',
279	    'video/webm': '.webm',
280	  };
281	  return map[mediaType] ?? '';
282	}
