173	export function zod3Schema<OBJECT>(
174	  zodSchema: z3.Schema<OBJECT, z3.ZodTypeDef, any>,
175	  options?: {
176	    /**
177	     * Enables support for references in the schema.
178	     * This is required for recursive schemas, e.g. with `z.lazy`.
179	     * However, not all language models and providers support such references.
180	     * Defaults to `false`.
181	     */
182	    useReferences?: boolean;
183	  },
184	): Schema<OBJECT> {
185	  // default to no references (to support openapi conversion for google)
186	  const useReferences = options?.useReferences ?? false;
187	
188	  return jsonSchema(
189	    // defer json schema creation to avoid unnecessary computation when only validation is needed
190	    () =>
191	      zod3ToJsonSchema(zodSchema, {
192	        $refStrategy: useReferences ? 'root' : 'none',
193	      }) as JSONSchema7,
194	    {
195	      validate: async value => {
196	        const result = await zodSchema.safeParseAsync(value);
197	        return result.success
198	          ? { success: true, value: result.data }
199	          : { success: false, error: result.error };
200	      },
201	    },
202	  );
203	}
