223	      addAdditionalPropertiesToJsonSchema(
224	        z4.toJSONSchema(zodSchema, {
225	          target: 'draft-7',
226	          io: 'input',
227	          reused: useReferences ? 'ref' : 'inline',
228	        }) as JSONSchema7,
