    // 2. Parse provider options via parseProviderOptions
    // 3. Build request body: { model, prompt, n, size?, style?, pixel_density?, seed? }
    // 4. POST to `${baseURL}/images/generate` via postJsonToApi
    // 5. Return { images, warnings, response, providerMetadata }
