import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type {
  FetchFunction,
  InferSchema,
  Resolvable,
} from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelArtFailedResponseHandler } from './pixelart-error';
import type { PixelArtImageModelId } from './pixelart-image-settings';

export interface PixelArtModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// Provider-specific options schema (passed via providerOptions.pixelart)
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Visual style of the generated pixel art image.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      /**
       * Number of pixels per unit cell. Higher values create a coarser,
       * more chunky pixel-art look. Accepts integers from 1 to 64.
       */
      pixelDensity: z.number().int().min(1).max(64).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// Minimal response schema — only what we need from the API
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      files,
      mask,
      providerOptions,
      abortSignal,
      headers,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // Warn about unsupported standard features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use `size` instead.',
      });
    }
    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details: 'PixelArt image generation does not support input images.',
      });
    }
    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt image generation does not support masks.',
      });
    }

    // Parse provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    // Build the request body
    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (size != null) {
      body.size = size;
    }
    if (seed != null) {
      body.seed = seed;
    }
    if (pixelArtOptions?.style != null) {
      body.style = pixelArtOptions.style;
    }
    if (pixelArtOptions?.pixelDensity != null) {
      body.pixel_density = pixelArtOptions.pixelDensity;
    }

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combinedHeaders,
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      providerMetadata: {
        pixelart: {
          images: response.data.map(() => ({
            created: response.created ?? undefined,
          })),
        },
      },
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

